mapper.select:
/* oms-interfaces-orderNonbatch-sql-oracle selectDecEncMalOrders */ WITH WITHKEY AS ( SELECT #{deckey} AS DECKEY , #{enckey} AS ENCKEY ) SELECT ROW_NUMBER() OVER() AS ROWNUM , ORGORDERKEY , DLVYMETHDCD , DLVYMETHDDTCD , CTKEY , MALORDERDIV , NISCNLRNGDIV , DLVYEXPCTDAY , ORDERISTDAY , PAYMTCOMPLDAY , BUYERZIPCD , RECPZIPCD , CMT , PARTERID , ADDCMT01 , ADDCMT02 , ADDCMT03 , pkg_crypto$encrypt(pkg_crypto$decrypt(BUYER, X.DECKEY), X.ENCKEY) AS BUYER , pkg_crypto$encrypt(pkg_crypto$decrypt(BUYERTEL01, X.DECKEY), X.ENCKEY) AS BUYERTEL01 , pkg_crypto$encrypt(pkg_crypto$decrypt(BUYERTEL02, X.DECKEY), X.ENCKEY) AS BUYERTEL02 , pkg_crypto$encrypt(pkg_crypto$decrypt(BUYERADDRHD, X.DECKEY), X.ENCKEY) AS BUYERADDRHD , pkg_crypto$encrypt(pkg_crypto$decrypt(BUYERADDRDT, X.DECKEY), X.ENCKEY) AS BUYERADDRDT , pkg_crypto$encrypt(pkg_crypto$decrypt(RECPNM, X.DECKEY), X.ENCKEY) AS RECPNM , pkg_crypto$encrypt(pkg_crypto$decrypt(RECPTEL01, X.DECKEY), X.ENCKEY) AS RECPTEL01 , pkg_crypto$encrypt(pkg_crypto$decrypt(RECPTEL02, X.DECKEY), X.ENCKEY) AS RECPTEL02 , pkg_crypto$encrypt(pkg_crypto$decrypt(RECPADDRHD, X.DECKEY), X.ENCKEY) AS RECPADDRHD , pkg_crypto$encrypt(pkg_crypto$decrypt(RECPADDRDT, X.DECKEY), X.ENCKEY) AS RECPADDRDT , pkg_crypto$encrypt(pkg_crypto$decrypt(ACCESSKEY, X.DECKEY), X.ENCKEY) AS ACCESSKEY FROM (
SELECT #{item.orgorderkey} AS ORGORDERKEY , #{item.dlvymethdcd} AS DLVYMETHDCD , #{item.dlvymethddtcd} AS DLVYMETHDDTCD , #{item.ctkey} AS CTKEY , #{item.malorderdiv} AS MALORDERDIV , #{item.niscnlrngdiv} AS NISCNLRNGDIV , #{item.dlvyexpctday} AS DLVYEXPCTDAY , #{item.orderistday} AS ORDERISTDAY , #{item.paymtcomplday} AS PAYMTCOMPLDAY , #{item.buyer} AS BUYER , #{item.buyertel01} AS BUYERTEL01 , #{item.buyertel02} AS BUYERTEL02 , #{item.buyerzipcd} AS BUYERZIPCD , #{item.buyeraddrhd} AS BUYERADDRHD , #{item.buyeraddrdt} AS BUYERADDRDT , #{item.recpnm} AS RECPNM , #{item.recptel01} AS RECPTEL01 , #{item.recptel02} AS RECPTEL02 , #{item.recpzipcd} AS RECPZIPCD , #{item.recpaddrhd} AS RECPADDRHD , #{item.recpaddrdt} AS RECPADDRDT , #{item.cmt} AS CMT , #{item.parterid} AS PARTERID , #{item.accesskey} AS ACCESSKEY , #{item.addcmt01} AS ADDCMT01 , #{item.addcmt02} AS ADDCMT02 , #{item.addcmt03} AS ADDCMT03
) T , WITHKEY X
